library(shiny)

NAVY   &lt;- "#0D1B2A"
AMBER  &lt;- "#C8762A"
BG     &lt;- "#FAFAF8"
BG2    &lt;- "#F5F0E8"
INK    &lt;- "#2C2420"
GRAPH  &lt;- "#8A7A68"
STONE  &lt;- "#B0A494"
RULE   &lt;- "#E0D8CC"
BORDER &lt;- "#D8CEBC"

ui &lt;- fluidPage(

  tags$head(tags$style(HTML(paste0("
    body, .shiny-frame { background:", BG, "; color:", INK, "; }

    .ctrl-panel {
      background:", BG2, ";
      border: 0.5px solid ", BORDER, ";
      border-top: 3px solid ", AMBER, ";
      border-radius: 4px;
      padding: 1.1rem 1.2rem;
      margin-top: 0.5rem;
    }
    .ctrl-label {
      font-family: 'Courier New', monospace;
      font-size: 0.85rem;
      letter-spacing: 0.15em;
      color: ", STONE, ";
      margin-bottom: 0.15rem;
      display: block;
    }
    .gamma-val {
      font-family: 'Courier New', monospace;
      font-size: 0.82rem;
      color: ", AMBER, ";
      margin-top: -0.3rem;
      margin-bottom: 0.6rem;
    }
    .ctrl-divider {
      border: none;
      border-top: 0.5px solid ", RULE, ";
      margin: 0.75rem 0;
    }
    .irs--shiny .irs-bar { background:", NAVY, "; border-color:", NAVY, "; }
    .irs--shiny .irs-handle { border-color:", AMBER, "; }
    .irs--shiny .irs-single { background:", NAVY, "; }
    .irs--shiny .irs-from,
    .irs--shiny .irs-to   { background:", NAVY, "; }
    .irs--shiny .irs-grid-pol { background:", RULE, "; }
    .irs--shiny .irs-line { background:", RULE, "; border-color:", RULE, "; }
    label.control-label { display: none; }
  ")))),

  fluidRow(
    column(12,
      plotOutput("upper_plot", height = "230px"),
      div(style = "height:6px"),
      plotOutput("lower_plot", height = "230px")
    )
  ),
  fluidRow(
    column(12,
      div(class = "ctrl-panel",
        span(class = "ctrl-label", style = "font-size: 1.5rem;", "Coefficient"),
        div(style = "width: 100%;",
          sliderInput("theta",
                      label = NULL, min = -1, max = 1, value = 0.5,
                      step = 0.05, ticks = FALSE, width = "100%")
        )
      )
    )
  )
)

server &lt;- function(input, output, session) {

  series &lt;- reactive({
    set.seed(42L)
    n     &lt;- 100L
    theta &lt;- input$theta
    eps   &lt;- rnorm(n + 1L)
    list(
      iid = eps[-1L],
      ma1 = eps[-1L] + theta * eps[-(n + 1L)],
      t   = seq_len(n)
    )
  })

  output$gamma_display &lt;- renderText({
    paste0("γ(1) = ", format(input$theta, nsmall = 2))
  })

  base_par &lt;- function() {
    par(
      bg        = BG,
      col.axis  = GRAPH,
      col.lab   = INK,
      col.main  = NAVY,
      family    = "serif",
      mar       = c(3, 3.8, 2.2, 0.8),
      mgp       = c(2.2, 0.5, 0),
      tcl       = -0.25,
      cex.axis  = 0.75,
      cex.lab   = 0.82,
      cex.main  = 0.88,
      font.main = 1
    )
  }

  ylims &lt;- reactive({
    s   &lt;- series()
    rng &lt;- range(c(s$iid, s$ma1))
    pad &lt;- diff(rng) * 0.06
    c(rng[1] - pad, rng[2] + pad)
  })

  output$upper_plot &lt;- renderPlot({
    s &lt;- series()
    base_par()
    plot(s$t, s$iid,
         type = "l", lwd = 1.0, col = NAVY,
         ylim = ylims(),
         main = expression(paste("iid  ", N(0,1), "  noise")),
         xlab = "", ylab = expression(Y[t]),
         bty = "l", xaxt = "n")
    abline(h = 0, col = RULE, lwd = 0.9)
  }, bg = BG)

  output$lower_plot &lt;- renderPlot({
    s     &lt;- series()
    theta &lt;- input$theta
    base_par()
    plot(s$t, s$ma1,
         type = "l", lwd = 1.2, col = AMBER,
         ylim = ylims(),
         main = bquote(
           MA(1): ~ Y[t] == epsilon[t] + .(theta) ~ epsilon[t-1] ~
           "    " ~ gamma(1) == .(theta)
         ),
         xlab = expression(t), ylab = expression(Y[t]),
         bty = "l")
    abline(h = 0, col = RULE, lwd = 0.9)
  }, bg = BG)
}

shinyApp(ui, server)

